// 1️⃣ Get raw markdown JSON text
const rawText = $input.first().json.text;

// 2️⃣ Extract JSON inside ```json ``` block
let parsed;
const match = rawText.match(/```json\s*([\s\S]*?)\s*```/i);
if (match) {
  parsed = JSON.parse(match[1]);
} else {
  parsed = JSON.parse(rawText);
}

// 3️⃣ Ensure outer tasks array exists
const outerTasks = Array.isArray(parsed.tasks) ? parsed.tasks : [];

// 4️⃣ Flatten into one item per step
const result = [];

outerTasks.forEach(taskGroup => {
  const taskId = taskGroup.task_id || null;

  const steps = Array.isArray(taskGroup.tasks)
    ? taskGroup.tasks
    : [];

  steps.forEach(step => {
    result.push({
      json: {
        task_id: taskId,
        task_step: Number(step.task_step),
        task_name: step.task_name
      }
    });
  });
});

return result;

// Get all incoming items
const tasks = $input.all().map(i => i.json);

// Group by task_id
const grouped = {};

tasks.forEach(task => {
  const id = task.task_id || "unknown";

  if (!grouped[id]) {
    grouped[id] = [];
  }

  grouped[id].push({
    step_number: Number(task.step_number),
    task_name: task.task_name
  });
});

// Build final formatted string
let formattedOutput = "";

const taskEntries = Object.entries(grouped);

taskEntries.forEach(([taskId, steps], index) => {

  // Sort steps numerically
  steps.sort((a, b) => a.step_number - b.step_number);

  // Build steps text
  const stepsText = steps
    .map(step => `Step ${step.step_number}: ${step.task_name}`)
    .join("\n");

  // Determine execution type
  const executionType = steps.length === 1 ? "parallel" : "sequential";

  // Append block
  formattedOutput += 
`task_id: ${taskId}
steps: ${stepsText}
execution_type: ${executionType}`;

  // Add spacing between task groups (except last one)
  if (index < taskEntries.length - 1) {
    formattedOutput += "\n\n";
  }
});

// Return single item
return [
  {
    json: {
      formatted_output: formattedOutput
    }
  }
];
